sql:
SELECT study_period_name
FROM study_periods
WHERE is_active = 1;

SELECT COUNT(*) AS total_active_courses
FROM course_variations
WHERE is_active = 1;

external_knowledge:
- 'top 3 maestros' refers to instructors with the highest number of enrolled students; 
- 'largest following of students' refers to the highest number of students enrolled in a course; 
- 'currently open classrooms' refers to study periods that are currently active (i.e., is_active = 1).

sql:
SELECT COUNT(*) AS active_study_periods
FROM study_periods
WHERE is_active = 1;

SELECT attendance_option_name, description
FROM attendance_options
WHERE is_online = 0;

SELECT course_name AS "Course Name"
FROM courses
ORDER BY course_name ASC;

SELECT COUNT(course_id) AS open_courses
FROM course_availability
WHERE is_open = 1 AND student_group_id = 0;
